void ILI_Intro(void)
{
	ILI_Invert();
	ILI_CLS();
	ILI_DrawPicture(6,121,graphics_Niedzielni,308,178);
	HAL_Delay(3000);
	uint8_t i = 0;
	for (i = 0; i < 20; i++)
	{
		ILI_DrawWhiteSector(100,299 - (i * 2),60,5);
		ILI_DrawPicture(6,121 - (i * 2),graphics_Niedzielni,308,178);
		HAL_Delay(2);
	}
	ILI_Invert();
	ILI_DrawPicture(6,296,graphics_Konfident,308,43);
	HAL_Delay(5000);
}

